import PropTypes from 'prop-types';
import { forwardRef } from 'react';

import {
  Wrapper,
  ImageWrapper,
  Text,
  Sponsored,
} from './RelatedArticlesCarouselItem.styles';

const RelatedArticlesCarouselItem = forwardRef(
  ({ href, title, image, isSponsored = false, isVisible, ...rest }, ref) => {
    return (
      <Wrapper {...rest} ref={ref} href={href} $isVisible={isVisible}>
        <ImageWrapper>{image}</ImageWrapper>
        <Text>
          {isSponsored && <Sponsored>sponsored</Sponsored>}
          {title}
        </Text>
      </Wrapper>
    );
  },
);

RelatedArticlesCarouselItem.displayName = 'RelatedArticlesCarouselItem';

RelatedArticlesCarouselItem.propTypes = {
  href: PropTypes.string.isRequired,
  title: PropTypes.string.isRequired,
  image: PropTypes.node,
  isSponsored: PropTypes.bool,
  isVisible: PropTypes.bool,
};

export default RelatedArticlesCarouselItem;
